-- Overview Module Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
-- Introduction
('bb-lesson-intro', 'bb-mod-overview', 'ballbeam-course', 'Introduction', 'Overview of the Ball and Beam project and what you will learn.', 'text',
'{"sections":[{"title":"Introduction","content":"In this program you will model and create a robust ball and beam controller by creating an engineering model, designing control loop architecture, and deploying code on a real control system."},{"title":"What You Will Build","content":"You will work with a collection of 3D printed parts, electronics, and a wooden platform originally developed by Ian Carey. This project will help you develop an understanding of control theory, physics, and software written in Python and C++. It includes a combination of model-based design and hands-on testing which are techniques used in industry for designing and deploying control systems."},{"title":"Learning Approach","content":"Throughout the program you will build your project incrementally using provided training materials, reference implementations, and various examples. These resources are designed to support you without removing the need for engineering decision making."},{"title":"Getting Help","content":"If you need help, email support@shortcct.com with your specific questions and a zip file including any files relevant to your project. Remember, virtual support is available for 3 months after your product delivery date."}],"key_points":["Build a robust ball and beam controller","Learn control theory, physics, and embedded programming","Use model-based design and hands-on testing","Virtual support available for 3 months"]}',
0, 10, 1),

-- Recommended Background
('bb-lesson-background', 'bb-mod-overview', 'ballbeam-course', 'Recommended Background', 'Prerequisites and helpful knowledge for this project.', 'text',
'{"sections":[{"title":"Recommended Background","content":"This project is designed for students who want hands-on control and embedded systems experience. You do not need a lot of experience, but some foundational knowledge is expected."},{"title":"Required Knowledge","content":"The following foundational knowledge is required to successfully complete this project:\n\n- **Basic knowledge of electronics** - Understanding of circuits, voltage, current, and basic components\n- **Introductory programming experience in C++ or Python** - Variables, loops, functions, and basic data structures"},{"title":"Helpful Knowledge","content":"The following knowledge is helpful but not strictly required:\n\n- **Introductory exposure to embedded systems** - Familiarity with microcontrollers and basic hardware interfacing\n- **Basic understanding of physics and signal theory** - Concepts like motion, forces, and signal processing"},{"title":"Need to Catch Up?","content":"If you find that you are missing some of this background, reach out to us at support@shortcct.com and we can explore options to get you up to speed!"}],"key_points":["Basic electronics knowledge required","C++ or Python programming experience required","Embedded systems exposure helpful","Physics and signal theory helpful"]}',
1, 10, 1),

-- Industry Alignment
('bb-lesson-industry', 'bb-mod-overview', 'ballbeam-course', 'Industry Alignment', 'How this project aligns with in-demand industry skills.', 'text',
'{"sections":[{"title":"Industry Alignment","content":"We analyzed the most in-demand skills across 50+ companies hiring embedded systems engineering interns. Below is how the Ball and Beam Project aligns with those skills."},{"title":"Skill Categories","content":"**Core skills** are fully covered in the base project.\n\n**Extendable skills** can be developed through optional project extensions and the design challenge.\n\n**Not Covered** indicates skills that are outside the scope of the core project."},{"title":"Skills Covered","content":"This project provides hands-on experience with:\n\n- PID control systems\n- Embedded systems programming\n- Sensor integration and signal processing\n- Motor control and actuation\n- Real-time systems\n- Filtering techniques\n- Circuit design and breadboarding"},{"title":"Documentation Resources","content":"The following external resources may be helpful during this project:\n\n- Control Stepper Motor with DRV8825 Driver Module & Arduino - Last Minute Engineers\n- How HC-SR04 Ultrasonic Sensor Works & Interface It With Arduino - Last Minute Engineers\n- Control Tutorials for MATLAB and Simulink - Ball & Beam: System Modeling"}],"key_points":["Skills aligned with industry internship requirements","Core skills fully covered in base project","Extendable skills through optional extensions","External documentation resources available"]}',
2, 10, 1);

