-- Training Material Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
-- Complete Project Overview
('bb-lesson-t-overview', 'bb-mod-training', 'ballbeam-course', 'Complete Project Overview', 'Watch this comprehensive overview of the entire Ball and Beam project.', 'video',
'{"video_url":"","video_type":"placeholder","sections":[{"title":"Overview Video Coming Soon","content":"A comprehensive video overview of the Ball and Beam project will be available here. This video will walk you through the complete system, demonstrate the final working product, and explain the learning objectives."},{"title":"What You Will Build","content":"A real-time embedded control system in which a microcontroller continuously reads the position of the ball, computes a corrective action, and commands a motor to adjust the beam angle."},{"title":"Learning Outcomes","content":"By the end of this program you will understand control theory, PID implementation, sensor integration, motor control, and professional embedded systems architecture."}],"resources":[{"title":"Ball & Beam System Modeling","url":"https://ctms.engin.umich.edu/CTMS/index.php?example=BallBeam&section=SystemModeling","type":"external"}]}',
0, 15, 1),

-- Basic Embedded Systems
('bb-lesson-t-embedded', 'bb-mod-training', 'ballbeam-course', 'Basic Embedded Systems', 'Learn the fundamentals of embedded systems programming for the Ball and Beam controller.', 'text',
'{"sections":[{"title":"Real-Time Embedded Control","content":"The Ball and Beam system operates as a real-time embedded control system in which a microcontroller continuously reads the position of the ball, computes a corrective action, and commands a motor to adjust the beam angle. Unlike traditional desktop programs that run once and terminate, embedded systems execute in a continuous loop."},{"title":"Arduino Program Structure","content":"In the Arduino environment, every program is organized around two core functions: setup() and loop().\n\n**setup()** runs once at startup and is used to initialize hardware components such as input/output pins, serial communication, sensors, and motor drivers.\n\n**loop()** runs repeatedly and forms the core control cycle of the system. Within this loop, the microcontroller repeatedly performs three essential steps: measure the ball''s position, calculate the control output, and update the actuator."},{"title":"Hardware Interfacing","content":"To interface with hardware, pins must be properly configured as inputs or outputs using pinMode(). Sensors such as potentiometers or distance sensors are typically read using analogRead(), which converts a voltage signal into a digital value using the microcontroller''s internal analog-to-digital converter.\n\nActuators such as motors are controlled using digital signals or Pulse Width Modulation (PWM). PWM allows the microcontroller to simulate an analog output by rapidly switching a pin on and off with a controllable duty cycle. In the Ball and Beam system, adjusting the PWM duty cycle changes the motor''s effective power, which in turn adjusts the beam angle."},{"title":"Timing in Control Systems","content":"Timing is a critical component of any control system. The control loop must run at consistent intervals to ensure stable and predictable behavior. Instead of using blocking delays that pause execution, embedded systems should rely on non-blocking timing methods such as millis() to maintain a steady loop frequency. This ensures the system remains responsive and capable of updating sensor readings and motor commands at a fixed rate. Consistent timing becomes especially important when implementing feedback control algorithms such as PID."},{"title":"Libraries and Abstraction","content":"Libraries are commonly used to simplify interaction with hardware components like ultrasonic sensors, servo motors, or communication modules. While these libraries abstract lower-level details, it is important to understand that they are configuring timers, managing communication protocols such as I2C or SPI, and handling signal timing behind the scenes. A strong embedded systems engineer understands not only how to call library functions, but also what those functions are doing internally."},{"title":"Serial Communication and Debugging","content":"Serial communication is an essential debugging tool in embedded development. By printing sensor values, control signals, and tuning parameters to the Serial Monitor, students can observe system behavior in real time and diagnose issues systematically. This mirrors professional engineering practice, where logging and measurement are critical for validating system performance."},{"title":"Foundation for Control","content":"By mastering these embedded fundamentals - program structure, hardware interfacing, PWM control, real-time timing, library usage, and serial debugging - students develop the foundation necessary to implement stable feedback control in the Ball and Beam system. These skills ensure that the software and hardware work together reliably before advancing to filtering and PID-based stabilization."}],"key_points":["Embedded systems run continuously in a loop","setup() initializes hardware, loop() runs control cycle","Use non-blocking timing methods like millis()","Serial debugging is essential for system validation","PWM controls motor speed and beam angle"]}',
1, 30, 1),

-- Circuit Creation and Breadboarding
('bb-lesson-t-circuits', 'bb-mod-training', 'ballbeam-course', 'Circuit Creation and Breadboarding', 'Learn to translate circuit schematics into physical breadboard implementations.', 'text',
'{"sections":[{"title":"Introduction","content":"Before the Ball and Beam system can be controlled in software, the hardware must be assembled correctly and safely. This section focuses on translating a circuit schematic into a physical breadboard implementation while understanding why each connection exists. The goal is not simply to \"wire it up,\" but to understand power flow, signal flow, grounding strategy, and component interaction."},{"title":"Power Distribution","content":"Every embedded circuit begins with power distribution. The microcontroller typically operates at 5V or 3.3V, and all sensors and logic components must share a common ground reference. On a breadboard, this means connecting the microcontroller''s GND to the ground rail and distributing VCC to the positive rail. Any sensor or driver module used in the system must connect to these same rails. A shared ground is essential; without it, voltage readings become meaningless and control signals behave unpredictably."},{"title":"Core Hardware Blocks","content":"The Ball and Beam system typically consists of three core hardware blocks: the microcontroller, the position sensor, and the motor driver.\n\n**Position Sensor:** The position sensor (such as a potentiometer, ultrasonic sensor, or IR distance sensor) provides a voltage or digital signal representing the ball''s location. This signal is routed to an analog or digital input pin on the microcontroller. Care must be taken to ensure voltage levels are within the allowable range of the microcontroller. If a sensor outputs 5V logic, the board must be 5V tolerant; otherwise, level shifting may be required.\n\n**Motor Driver:** The motor cannot be driven directly from a microcontroller pin because microcontroller pins can only source a small amount of current. Instead, a motor driver or transistor-based switching circuit must be used. For DC motors, this may involve an H-bridge driver module. For servos, a PWM signal wire is connected directly to a control pin, while power is supplied separately if higher current is required. The motor driver acts as a power interface, allowing the low-power logic signal to control a higher-power actuator safely."},{"title":"Structured Wiring Practices","content":"When placing components on a breadboard, students should follow structured wiring practices:\n\n- Keep power and ground rails organized\n- Use consistent wire colors (e.g., red for VCC, black for GND)\n- Keep signal wires short to reduce noise\n- Avoid crossing wires unnecessarily\n- Route high-current motor wires separately from sensitive sensor lines when possible\n\nPoor wiring layout can introduce electrical noise, unstable readings, or intermittent failures."},{"title":"Decoupling Capacitors","content":"Decoupling capacitors are also an important practical consideration. Placing small capacitors (e.g., 0.1 uF) across power and ground near sensitive components helps filter voltage spikes and noise caused by motors switching on and off. Motors are inductive loads and can introduce electrical disturbances into the system if not properly managed."},{"title":"Incremental Verification","content":"Students should verify their circuit incrementally:\n\n1. First confirm that power rails supply the correct voltage using a multimeter\n2. Next test the sensor independently by printing readings to the Serial Monitor\n3. Then test motor actuation with a simple fixed PWM signal before integrating the full control algorithm\n\nBuilding and validating one subsystem at a time prevents compounding errors and simplifies debugging."},{"title":"From Breadboard to PCB","content":"Understanding circuit creation at the breadboard level builds intuition about how real embedded systems are implemented. It reinforces the relationship between schematics and physical hardware, teaches safe power handling practices, and prepares students to move beyond prototyping toward PCB-based designs in the future."}],"key_points":["All components must share a common ground","Use structured wiring with consistent wire colors","Motor drivers are required - never drive motors directly","Decoupling capacitors filter noise from motors","Verify circuit incrementally - one subsystem at a time"]}',
2, 35, 1),

-- Motors and Motor Controllers
('bb-lesson-t-motors', 'bb-mod-training', 'ballbeam-course', 'Motors and Motor Controllers', 'Understand motor operation and safe control methods for the Ball and Beam system.', 'text',
'{"sections":[{"title":"Introduction","content":"The Ball and Beam system relies on a motor to adjust the angle of the beam in response to the ball''s position. Understanding how motors work - and how to control them safely - is essential for building a stable and reliable control system. This section introduces the fundamentals of motor operation, the limitations of microcontrollers, and the role of motor driver circuits."},{"title":"Motor Basics","content":"At a basic level, a motor converts electrical energy into mechanical motion. In this project, the motor''s job is to rotate a shaft that tilts the beam. Depending on the design, this may be a DC motor, a servo motor, or a stepper motor. Each type has different control characteristics:\n\n**DC Motor:** Spins continuously when voltage is applied and requires external circuitry to control speed and direction.\n\n**Servo Motor:** Contains internal control electronics and moves to a commanded position based on a PWM control signal.\n\n**Stepper Motor:** Moves in discrete angular steps and is commonly used when precise positioning is required."},{"title":"Why Motor Drivers Are Necessary","content":"Microcontrollers cannot power motors directly because motors require significantly more current than a microcontroller pin can provide. Attempting to drive a motor directly from a pin can permanently damage the board. Instead, a motor controller - also called a motor driver - is used as an interface between the low-power logic signals and the higher-power motor supply. The microcontroller sends control signals to the driver, and the driver handles the higher current switching required to power the motor."},{"title":"DC Motor Control with H-Bridge","content":"For DC motors, an H-bridge driver is commonly used. An H-bridge allows both speed control and direction control by switching current flow through the motor in either direction. Speed is typically controlled using PWM. By adjusting the duty cycle of the PWM signal, the average voltage across the motor changes, which adjusts the motor''s speed and torque. Direction is controlled by toggling logic inputs on the driver."},{"title":"Servo Motor Control","content":"For servo motors, control is typically simpler. A servo uses a single PWM control line where the pulse width determines the angular position. Internally, the servo contains a feedback mechanism that ensures the shaft moves to and holds the commanded position. In many Ball and Beam designs, a servo simplifies implementation because it removes the need for a separate feedback loop for beam angle."},{"title":"Stepper Motor Control","content":"For stepper motors, a stepper driver module generates the required coil switching sequences. The microcontroller typically sends step and direction signals to the driver. Steppers provide precise incremental movement but require careful control to prevent missed steps or excessive current draw."},{"title":"Power Management","content":"Power management is critical when working with motors. Motors can draw large currents, especially during startup or stall conditions. A separate power supply is often required for the motor, and all grounds must be connected together to maintain a common reference. Additionally, motors are inductive loads and can generate voltage spikes when switching. Motor drivers include protective components such as flyback diodes to prevent damage from these spikes."},{"title":"Testing Before Control","content":"When integrating the motor into the Ball and Beam system, it is important to test motor behavior independently before implementing feedback control. Start with fixed PWM signals or fixed position commands. Observe how the beam responds. Identify mechanical limits, dead zones, and nonlinearities. This practical understanding will be critical when tuning the control algorithm."},{"title":"Foundation for Actuation","content":"By understanding how motors operate, why motor drivers are necessary, and how control signals translate into mechanical motion, students gain the ability to design safe and effective actuator systems. This knowledge forms the foundation for implementing precise beam angle control in the closed-loop Ball and Beam system."}],"key_points":["Motors convert electrical energy to mechanical motion","Motor drivers are required - microcontrollers cannot power motors directly","DC motors use H-bridge for speed and direction control","Servo motors use PWM pulse width for position control","Test motor behavior independently before implementing control"]}',
3, 30, 1),

-- Distance Sensing
('bb-lesson-t-sensing', 'bb-mod-training', 'ballbeam-course', 'Distance Sensing', 'Learn how position sensors provide feedback for the control system.', 'text',
'{"sections":[{"title":"Foundation of Feedback Control","content":"Accurate position measurement is the foundation of the Ball and Beam control system. The motor adjusts the beam angle, but the system can only stabilize the ball if it knows where the ball is at all times. Distance sensing provides the feedback signal that makes closed-loop control possible.\n\nIn this project, the sensor measures the ball''s position along the length of the beam. Depending on the hardware design, this may be accomplished using an ultrasonic sensor, an infrared (IR) distance sensor, or a linear potentiometer mechanism. Regardless of the sensor type, the goal is the same: convert physical position into an electrical signal that the microcontroller can read and process."},{"title":"Ultrasonic Sensors","content":"An ultrasonic sensor works by emitting a short pulse of sound and measuring the time it takes for the echo to return after reflecting off the ball. Because the speed of sound is known, the time-of-flight measurement can be converted into distance.\n\nThese sensors typically use a trigger pin and an echo pin. The microcontroller sends a short trigger pulse, then measures how long the echo pin remains high. Libraries are often used to simplify this timing process, but it is important to understand that the distance calculation is based on precise microsecond timing."},{"title":"Infrared Distance Sensors","content":"Infrared distance sensors operate differently. They emit infrared light and measure the intensity or angle of the reflected signal. These sensors usually provide an analog voltage output that varies with distance. The microcontroller reads this voltage using analogRead() and converts the raw value into a physical distance measurement using calibration data."},{"title":"Noise and Filtering","content":"Regardless of the sensing method, raw measurements are rarely perfect. Sensor readings may contain noise, small fluctuations, or occasional outliers. Electrical noise from the motor, mechanical vibrations, and environmental conditions can all affect measurement quality. For this reason, filtering techniques - such as moving averages or exponential smoothing - are often applied to stabilize the signal before it is used in the control algorithm."},{"title":"Calibration","content":"Calibration is another critical step. The raw sensor output must be mapped to actual physical distances along the beam. This often involves placing the ball at known positions, recording sensor readings, and generating a conversion equation or lookup table. Without calibration, the control system may respond incorrectly because it is acting on inaccurate position estimates."},{"title":"Sampling Rate","content":"Sampling rate is also important. The sensor must be read at consistent intervals within the main control loop. If readings are taken too slowly, the system becomes sluggish and unstable. If readings are too fast without proper filtering, noise may dominate the signal. A balanced, consistent update rate ensures accurate and stable feedback."},{"title":"Sensor Importance","content":"In a closed-loop control system like Ball and Beam, the sensor is just as important as the motor. A powerful actuator cannot compensate for poor measurements. By understanding how distance sensors operate, how to interpret and calibrate their signals, and how to manage noise, students build the measurement foundation required for stable and responsive control."}],"key_points":["Position sensing enables closed-loop control","Ultrasonic sensors use time-of-flight measurement","IR sensors provide analog voltage proportional to distance","Filtering is essential to reduce noise","Calibration maps sensor values to physical distances","Consistent sampling rate is critical for stability"]}',
4, 30, 1),

-- Filtering Techniques
('bb-lesson-t-filtering', 'bb-mod-training', 'ballbeam-course', 'Filtering Techniques', 'Learn signal processing methods to improve sensor measurements.', 'text',
'{"sections":[{"title":"Why Filtering Is Essential","content":"Filtering is a fundamental requirement in real-world control systems because sensors do not operate under ideal conditions. They introduce noise, measurement jitter, dropouts, and occasional spikes. In the Ball and Beam system, the HC-SR04 ultrasonic sensor is particularly susceptible to these issues. Its readings can fluctuate due to surface reflections, beam angle variation, vibration, and electrical noise generated by the motor.\n\nIf unfiltered measurements are used directly in a feedback controller, system performance can degrade significantly. The derivative term of a PID controller is especially sensitive to this problem because it estimates how fast the ball is moving based on changes in position. Since the derivative is based on rate of change, even small measurement spikes can produce large derivative outputs, effectively amplifying noise and causing aggressive, unstable motor corrections.\n\nProper filtering improves stability, reduces oscillation, and produces smoother actuator behavior without sacrificing responsiveness."},{"title":"Exponential Moving Average (EMA)","content":"One of the most practical filtering techniques for embedded systems is the Exponential Moving Average (EMA) filter. The EMA is a first-order low-pass, infinite impulse response (IIR) filter. It is called \"infinite impulse response\" because each output depends on both the current measurement and the previous filtered output, meaning past inputs influence the result with exponentially decreasing weight.\n\nThe EMA is defined by the equation:\n\n**y_k = alpha * x_k + (1 - alpha) * y_(k-1)**\n\nWhere:\n- x_k is the new measurement\n- y_k is the filtered output\n- y_(k-1) is the previous filtered output\n- alpha is a constant between 0 and 1\n\nThe parameter alpha determines how aggressive the filter is. When alpha is small, the filter heavily smooths the signal and reduces noise but responds more slowly to real changes. When alpha is large, the filter responds quickly but provides less smoothing.\n\nBecause the EMA only requires storing the previous output value, it is computationally efficient and well-suited for microcontrollers with limited memory. In the Ball and Beam system, applying an EMA filter to ultrasonic sensor readings significantly reduces jitter and prevents large derivative spikes in the PID controller."},{"title":"Kalman Filter","content":"A more advanced filtering approach is the Kalman filter. The Kalman filter is an optimal recursive estimation algorithm used to estimate the state of a linear system from noisy and incomplete measurements. While mathematically more complex than the EMA, its core idea is straightforward: it combines a prediction of system behavior with the measured sensor value to produce a more accurate estimate than either would alone.\n\nIn the Ball and Beam system, the Kalman filter can estimate ball position and even velocity by blending a motion model with noisy ultrasonic measurements. It works in two steps:\n\n**Prediction:** The system''s next state is estimated based on previous behavior\n**Correction:** That prediction is adjusted using the new measurement\n\nThe filter automatically balances how much it trusts the model versus the measurement based on predefined uncertainty parameters. For this project, it is acceptable to treat the Kalman filter as a structured estimation tool implemented through a library, rather than focusing on its full mathematical derivation."},{"title":"Practical Recommendations","content":"In practice, the EMA filter is recommended as a starting point due to its simplicity and effectiveness. The Kalman filter can be introduced later for improved estimation performance, particularly when velocity estimation or high noise levels are present.\n\nRegardless of the method chosen, filtering is not optional in practical control systems. Clean measurements are essential for stable feedback control, and applying proper filtering techniques ensures that the Ball and Beam system responds smoothly, accurately, and reliably."}],"key_points":["Raw sensor measurements contain noise and spikes","PID derivative term is especially sensitive to noise","EMA filter is simple and effective for embedded systems","Alpha parameter controls smoothing vs responsiveness tradeoff","Kalman filter provides optimal estimation but is more complex","Filtering is essential - not optional - for stable control"]}',
5, 35, 1),

-- PID Control
('bb-lesson-t-pid', 'bb-mod-training', 'ballbeam-course', 'PID Control', 'Understand the theory and practice of PID feedback control.', 'text',
'{"sections":[{"title":"Building Intuition for PID","content":"This section focuses on building an intuitive understanding of PID control - what each term does, how it affects system behavior, and how to tune the gains manually. In the Ball and Beam system, PID control is used to stabilize the ball at a desired position by adjusting the beam angle through the motor. Rather than treating PID as a formula to memorize, the goal is to understand how each component influences motion and stability."},{"title":"Closed-Loop Feedback System","content":"A PID controller operates within a closed-loop feedback system. The sensor measures the ball''s position (the process variable) and sends that measurement to the controller. The controller compares this measured value to the desired position (the setpoint) and computes the error, which is simply the difference between the two. Based on this error, the PID algorithm calculates a control output that drives the actuator (motor or servo), which changes the beam angle and influences the ball''s motion. This loop runs continuously, constantly correcting deviations.\n\nConceptually, the system can be described as follows:\n1. The setpoint is compared with the measured position to produce an error signal\n2. That error enters the PID controller\n3. The PID controller generates a control signal that drives the actuator\n4. The actuator affects the physical system (beam angle and ball motion)\n5. The sensor then measures the new position, and the loop repeats"},{"title":"Proportional Term (P)","content":"The proportional term reacts to the present error. If the ball is far from the center, the proportional term generates a large corrective action. Increasing the proportional gain (Kp) makes the system respond more aggressively.\n\n**However:** Too much proportional gain can cause oscillation or instability. The system may overshoot the target and keep swinging back and forth."},{"title":"Integral Term (I)","content":"The integral term reacts to accumulated past error. If the ball settles slightly off-center and stays there, the integral term slowly builds up and pushes the system toward eliminating steady-state error.\n\nIncreasing the integral gain (Ki) improves long-term accuracy but can introduce overshoot and slow oscillations if too large."},{"title":"Derivative Term (D)","content":"The derivative term reacts to the rate of change of the error. It predicts future behavior by observing how quickly the ball is moving. If the ball is moving rapidly toward the setpoint, the derivative term reduces the control effort to prevent overshoot.\n\nIncreasing the derivative gain (Kd) improves damping and reduces oscillations, but too much derivative gain can amplify noise and create erratic behavior."},{"title":"Essential Terminology","content":"Several terms are essential when discussing PID control in the Ball and Beam system:\n\n**Process Variable:** The measured quantity being controlled - in this case, the ball''s position along the beam\n\n**Setpoint:** The desired value of the process variable, typically the center of the beam\n\n**Error:** The difference between the setpoint and the measured position\n\n**Actuator:** The device that influences the system, such as the motor or servo adjusting the beam angle\n\n**Control Signal:** The output of the PID controller that drives the actuator"},{"title":"Manual Tuning Approach","content":"Manual tuning is an important skill in embedded control systems. A common approach is:\n\n1. Begin with Ki and Kd set to zero\n2. Increase Kp until the system responds quickly but begins to oscillate slightly\n3. Introduce derivative gain (Kd) to reduce oscillation and improve damping\n4. Add a small amount of integral gain (Ki) to eliminate steady-state error\n\nThe goal is to achieve a balance between responsiveness, stability, and accuracy. Tuning is iterative and requires observing system behavior carefully."},{"title":"Why PID Works","content":"PID controllers are widely used in engineering because they are both simple and powerful. They capture:\n\n- **The present** through proportional action\n- **The past** through integration\n- **The future** through differentiation (rate of change)\n\nBy developing an intuition for how each gain affects motion, students gain the ability to stabilize not only the Ball and Beam system, but also a wide range of real-world control systems involving speed, position, temperature, pressure, and voltage."}],"key_points":["PID operates in a closed-loop feedback system","P responds to current error - higher Kp means faster response","I eliminates steady-state error by accumulating past error","D predicts future error and reduces overshoot","Tune in order: Kp first, then Kd, then Ki","Balance responsiveness, stability, and accuracy"]}',
6, 40, 1);

