INSERT INTO course_modules (id, course_id, title, description, order_index, is_published)
VALUES ('bb-mod-controller', 'ballbeam-course', 'Module: Controller Implementation', 'Bring the Ball and Beam system to life by integrating sensing, filtering, and actuation into a complete closed-loop PID controller. By the end of this module, the system should stabilize the ball at a desired setpoint and recover from small disturbances.', 2, 1);

-- Controller Implementation Lessons
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, content_json, order_index, duration_minutes, is_published)
VALUES 
-- Task 1: Real-Time Control Loop
('bb-lesson-task1', 'bb-mod-controller', 'ballbeam-course', 'Task 1: Implement the Real-Time Control Loop', 'Configure a fixed-interval control loop that runs deterministically.', 'text',
'{"sections":[{"title":"Objective","content":"Configure a fixed-interval control loop that runs deterministically. The loop should execute at a consistent sampling rate (for example, every 10 ms). All sensing, PID computation, and actuator updates must occur inside this timed loop."},{"title":"Implementation Guidance","content":"Follow these guidelines when implementing your control loop:\n\n- Use a non-blocking timing method (such as millis() or a hardware timer) to maintain a constant loop interval\n- Store the loop interval in seconds for proper integral and derivative calculation\n- Ensure that sensor readings are filtered before entering the PID equation\n- Print loop timing and position values to Serial during early testing"},{"title":"Code Structure","content":"```cpp\n// In main.cpp\nunsigned long lastControlTime = 0;\nconst unsigned long CONTROL_INTERVAL_MS = 10;  // 10ms = 100Hz\nconst float dt = CONTROL_INTERVAL_MS / 1000.0f;  // Convert to seconds\n\nvoid loop() {\n    unsigned long currentTime = millis();\n    \n    if (currentTime - lastControlTime >= CONTROL_INTERVAL_MS) {\n        lastControlTime = currentTime;\n        \n        // 1. Read and filter sensor\n        float position = readFilteredPosition();\n        \n        // 2. Compute PID output\n        float controlOutput = computePID(position, setpoint, dt);\n        \n        // 3. Update actuator\n        setMotorPosition(controlOutput);\n        \n        // Debug output\n        Serial.print(\"Pos: \");\n        Serial.print(position);\n        Serial.print(\" Output: \");\n        Serial.println(controlOutput);\n    }\n}\n```"},{"title":"Why Consistent Timing Matters","content":"The PID algorithm relies on knowing the time between samples (dt) to correctly compute integral and derivative terms. If the loop runs at inconsistent intervals, the controller will behave unpredictably.\n\nUsing non-blocking timing (millis() instead of delay()) ensures other system tasks can run if needed and the system remains responsive."},{"title":"Testing Your Loop","content":"Before implementing PID, verify that:\n\n1. The loop runs at the expected interval (check with Serial timestamps)\n2. Sensor readings are being filtered properly\n3. Motor responds to fixed test values\n\nOnly proceed to PID implementation once the control loop timing is verified."}],"key_points":["Use non-blocking timing with millis()","Store dt in seconds for PID calculations","Filter sensor readings before PID","Print debug values during development","Verify timing before implementing PID"]}',
0, 45, 1),

-- Task 2: PID Algorithm
('bb-lesson-task2', 'bb-mod-controller', 'ballbeam-course', 'Task 2: Implement the PID Algorithm', 'Write the PID controller logic using proportional, integral, and derivative terms.', 'text',
'{"sections":[{"title":"Objective","content":"Write the PID controller logic using proportional, integral, and derivative terms. The controller should compute the control output based on the error between the setpoint and measured ball position."},{"title":"Implementation Guidance","content":"Follow these guidelines when implementing your PID controller:\n\n- Define global variables for Kp, Ki, and Kd\n- Compute error as setpoint minus measured position\n- Accumulate the integral term using error multiplied by dt\n- Compute the derivative term using the change in error divided by dt\n- Store the previous error for the next iteration\n- Constrain the control output to safe actuator limits\n- Implement integral windup protection by clamping the integral term"},{"title":"Code Structure","content":"```cpp\n// controller.h\n#ifndef CONTROLLER_H\n#define CONTROLLER_H\n\nvoid initController();\nfloat computePID(float measured, float setpoint, float dt);\nvoid setGains(float kp, float ki, float kd);\nvoid resetIntegral();\n\n#endif\n\n// controller.cpp\n#include \"controller.h\"\n\nfloat Kp = 0.0;\nfloat Ki = 0.0;\nfloat Kd = 0.0;\n\nfloat integral = 0.0;\nfloat previousError = 0.0;\n\nconst float INTEGRAL_LIMIT = 100.0;  // Prevent windup\nconst float OUTPUT_MIN = -90.0;       // Actuator limits\nconst float OUTPUT_MAX = 90.0;\n\nvoid initController() {\n    integral = 0.0;\n    previousError = 0.0;\n}\n\nvoid setGains(float kp, float ki, float kd) {\n    Kp = kp;\n    Ki = ki;\n    Kd = kd;\n}\n\nfloat computePID(float measured, float setpoint, float dt) {\n    // Calculate error\n    float error = setpoint - measured;\n    \n    // Proportional term\n    float P = Kp * error;\n    \n    // Integral term with anti-windup\n    integral += error * dt;\n    integral = constrain(integral, -INTEGRAL_LIMIT, INTEGRAL_LIMIT);\n    float I = Ki * integral;\n    \n    // Derivative term\n    float derivative = (error - previousError) / dt;\n    float D = Kd * derivative;\n    \n    // Store for next iteration\n    previousError = error;\n    \n    // Compute and constrain output\n    float output = P + I + D;\n    output = constrain(output, OUTPUT_MIN, OUTPUT_MAX);\n    \n    return output;\n}\n\nvoid resetIntegral() {\n    integral = 0.0;\n}\n```"},{"title":"Integral Windup Protection","content":"Without limits, the integral term can grow very large if the system cannot reach the setpoint (e.g., if the ball is removed). This \"windup\" causes delayed and excessive response when normal operation resumes.\n\nClamping the integral term to a reasonable range prevents this issue."},{"title":"Derivative Filtering","content":"The derivative term is sensitive to noise. If your sensor is noisy, consider:\n\n1. Filtering the sensor reading before PID (recommended)\n2. Filtering the derivative term itself\n3. Computing derivative on measurement rather than error"}],"key_points":["Error = setpoint - measured","Integral accumulates error over time","Derivative uses change in error","Constrain output to actuator limits","Implement integral windup protection","Store previous error for derivative calculation"]}',
1, 60, 1),

-- Task 3: Motor Driver Integration
('bb-lesson-task3', 'bb-mod-controller', 'ballbeam-course', 'Task 3: Integrate the Motor Driver', 'Convert the PID output into valid actuator commands.', 'text',
'{"sections":[{"title":"Objective","content":"Convert the PID output into a valid actuator command that safely drives the motor or servo controlling the beam."},{"title":"Implementation Guidance","content":"Follow these guidelines when integrating your motor driver:\n\n- Map the PID output to a PWM value or servo angle\n- Respect mechanical angle limits of the beam\n- Ensure smooth transitions when switching motor direction\n- Test actuator response independently before running full PID control\n- Add safety constraints to prevent sustained maximum output"},{"title":"Code Structure","content":"```cpp\n// actuator.h\n#ifndef ACTUATOR_H\n#define ACTUATOR_H\n\nvoid initActuator();\nvoid setBeamAngle(float angle);  // Input: degrees from horizontal\nvoid disableActuator();\nbool isActuatorEnabled();\n\n#endif\n\n// actuator.cpp\n#include <Servo.h>\n#include \"actuator.h\"\n\nServo beamServo;\n\nconst int SERVO_PIN = 9;\nconst int SERVO_CENTER = 90;      // Neutral position\nconst int SERVO_MIN = 45;         // Physical limit\nconst int SERVO_MAX = 135;        // Physical limit\nconst float ANGLE_TO_SERVO = 1.0; // Conversion factor\n\nbool enabled = false;\n\nvoid initActuator() {\n    beamServo.attach(SERVO_PIN);\n    beamServo.write(SERVO_CENTER);\n    enabled = true;\n}\n\nvoid setBeamAngle(float angle) {\n    if (!enabled) return;\n    \n    // Convert PID output (degrees) to servo position\n    int servoPos = SERVO_CENTER + (int)(angle * ANGLE_TO_SERVO);\n    \n    // Constrain to physical limits\n    servoPos = constrain(servoPos, SERVO_MIN, SERVO_MAX);\n    \n    beamServo.write(servoPos);\n}\n\nvoid disableActuator() {\n    beamServo.write(SERVO_CENTER);\n    enabled = false;\n}\n\nbool isActuatorEnabled() {\n    return enabled;\n}\n```"},{"title":"Mapping PID Output to Actuator","content":"The PID controller outputs a value representing the desired beam angle (or angular correction). This must be mapped to the specific actuator being used:\n\n**For Servos:** Map angle to servo position (typically 0-180 degrees)\n**For DC Motors with H-Bridge:** Map to PWM duty cycle and direction pins\n**For Stepper Motors:** Convert angle to step count"},{"title":"Safety Considerations","content":"Always implement safety limits:\n\n1. **Physical limits:** Prevent the beam from hitting mechanical stops\n2. **Rate limiting:** Avoid sudden large movements that could destabilize the system\n3. **Disable function:** Provide a way to safely stop the actuator\n4. **Timeout protection:** Disable if no valid commands received for extended period"},{"title":"Testing Procedure","content":"Before integrating with PID:\n\n1. Send fixed angle commands and verify beam moves correctly\n2. Test both positive and negative angles\n3. Verify neutral position is truly horizontal\n4. Check that physical limits are not exceeded\n5. Test the disable function"}],"key_points":["Map PID output to actuator command range","Respect mechanical limits of the beam","Test actuator independently before PID integration","Implement safety constraints","Provide disable function for safe shutdown"]}',
2, 45, 1),

-- Task 4: Controller Tuning
('bb-lesson-task4', 'bb-mod-controller', 'ballbeam-course', 'Task 4: Tune the Controller', 'Tune the PID gains manually to achieve stable and responsive behavior.', 'text',
'{"sections":[{"title":"Objective","content":"Tune the PID gains manually to achieve stable and responsive behavior."},{"title":"Implementation Guidance","content":"Follow these guidelines when tuning your controller:\n\n- Begin with Ki and Kd set to zero\n- Increase Kp gradually until the system begins to oscillate\n- Introduce Kd to reduce oscillation and improve damping\n- Add a small Ki to eliminate steady-state error\n- Change one gain at a time and observe system response\n- Record final gain values and performance observations"},{"title":"Tuning Procedure","content":"**Step 1: Proportional Only**\n\nSet Ki = 0 and Kd = 0. Start with a small Kp value (e.g., 0.5) and gradually increase it.\n\nObserve:\n- Does the ball move toward the center?\n- Does it overshoot and oscillate?\n- How quickly does it respond to disturbances?\n\nFind the value where the system responds quickly but just begins to oscillate. This is your starting Kp.\n\n**Step 2: Add Derivative**\n\nKeep Kp at the value found above. Start increasing Kd from 0.\n\nObserve:\n- Does oscillation decrease?\n- Does the system respond smoothly without overshoot?\n- Is the response too sluggish?\n\nFind the value that eliminates most oscillation without making the system too slow.\n\n**Step 3: Add Integral (If Needed)**\n\nIf the ball consistently settles slightly off-center (steady-state error), add a small Ki.\n\nObserve:\n- Does the ball eventually reach the exact center?\n- Does adding Ki cause slow oscillations?\n- Is the system still stable?\n\nUse the smallest Ki that eliminates steady-state error."},{"title":"Documentation","content":"Keep a log of your tuning process:\n\n```\nTest 1: Kp=0.5, Ki=0, Kd=0\n  Result: Ball moves slowly, doesn''t reach center\n\nTest 2: Kp=1.0, Ki=0, Kd=0\n  Result: Faster response, slight overshoot\n\nTest 3: Kp=1.5, Ki=0, Kd=0\n  Result: Continuous oscillation\n\nTest 4: Kp=1.2, Ki=0, Kd=0.3\n  Result: Oscillation reduced, smooth response\n\nTest 5: Kp=1.2, Ki=0.05, Kd=0.3\n  Result: Reaches center exactly, stable\n  FINAL VALUES\n```"},{"title":"Troubleshooting","content":"**System oscillates continuously:**\n- Reduce Kp\n- Increase Kd\n- Check for sensor noise\n\n**System responds too slowly:**\n- Increase Kp\n- Reduce Kd if too high\n\n**Ball settles off-center:**\n- Add or increase Ki\n- Check sensor calibration\n\n**System is erratic/unstable:**\n- Check sensor filtering\n- Reduce all gains and start over\n- Verify control loop timing"}],"key_points":["Start with Ki=0 and Kd=0","Increase Kp until slight oscillation","Add Kd to reduce oscillation","Add small Ki only if needed for steady-state error","Change one parameter at a time","Document all tuning attempts"]}',
3, 60, 1),

-- Module Demo Submission
('bb-lesson-demo', 'bb-mod-controller', 'ballbeam-course', 'Controller Implementation Demo', 'Submit a video demonstrating your completed Ball and Beam controller.', 'submission',
'{"instructions":"Record a video demonstrating your completed Ball and Beam controller implementation. Your video should show:\n\n1. **System Overview** - Brief view of your hardware setup\n2. **Ball Stabilization** - Ball being stabilized at center position\n3. **Disturbance Recovery** - Push the ball and show it returning to center\n4. **Setpoint Changes** - If implemented, show the ball tracking different positions\n\n**Video Requirements:**\n- 1 to 3 minutes in length\n- Show the physical system clearly\n- Demonstrate each feature working\n- Brief verbal or text explanation of your approach\n\n**Upload your project files as a ZIP including:**\n- controller.h and controller.cpp (PID implementation)\n- actuator.h and actuator.cpp (motor control)\n- sensor.h and sensor.cpp (filtered position measurement)\n- main.cpp (system coordination and control loop)\n\n**No PID calculations, filtering logic, or motor control code should be written directly inside main.cpp beyond high-level coordination.**","submission_type":"video","required_files":["controller.h","controller.cpp","actuator.h","actuator.cpp","sensor.h","sensor.cpp","main.cpp"],"rubric":[{"criteria":"Real-time control loop","points":20,"description":"Fixed-interval control loop running at consistent rate with proper timing"},{"criteria":"PID implementation","points":25,"description":"Correct PID algorithm with integral windup protection and proper dt usage"},{"criteria":"Motor integration","points":20,"description":"Safe actuator control with proper limits and smooth operation"},{"criteria":"Controller tuning","points":20,"description":"System stabilizes ball and recovers from disturbances"},{"criteria":"Code quality","points":15,"description":"Clean file structure, proper abstractions, documented code"}]}',
4, 30, 1),

